//\! Validates benchmarks compile and produce reasonable output
//\! Run with: cargo test --test benchmarks_validate

use std::process::Command;
use std::time::Duration;
use tracing::{info, warn, error, debug};

fn init_logging() {
    let _ = tracing_subscriber::fmt()
        .with_max_level(tracing::Level::DEBUG)
        .try_init();
}

#[test]
fn benchmarks_compile() {
    init_logging();
    info\!("Validating benchmark compilation");

    let output = Command::new("cargo")
        .args(["build", "--benches"])
        .output()
        .expect("Failed to run cargo");

    if \!output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        error\!(stderr = stderr.as_ref(), "Benchmark compilation failed");
        panic\!("Benchmarks failed to compile");
    }

    info\!("All benchmarks compile successfully");
}

#[test]
fn benchmark_quick_run() {
    init_logging();
    info\!("Running benchmarks in quick mode");

    // Run each benchmark for minimal iterations
    let output = Command::new("cargo")
        .args([
            "bench", 
            "--", 
            "--test",  // Run each benchmark once
            "--warm-up-time", "1",
            "--measurement-time", "1",
        ])
        .timeout(Duration::from_secs(60))
        .output()
        .expect("Failed to run benchmarks");

    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);

    debug\!(stdout = stdout.as_ref(), "Benchmark stdout");
    debug\!(stderr = stderr.as_ref(), "Benchmark stderr");

    // Check for panics or errors
    assert\!(
        \!stderr.contains("panicked") && \!stderr.contains("error[E"),
        "Benchmarks should not panic or error"
    );

    info\!("Benchmark quick run completed successfully");
}
```

### 2. Performance Baseline Script

Create `scripts/benchmark_baseline.sh`:

```bash
#\!/bin/bash
# Generate and store performance baselines
# Usage: ./scripts/benchmark_baseline.sh [baseline_name]

set -euo pipefail

BASELINE_NAME="${1:-$(git rev-parse --short HEAD)}"
BASELINE_DIR="target/criterion/baselines"
LOG_FILE="target/benchmark_${BASELINE_NAME}.log"

mkdir -p "$BASELINE_DIR"

echo "=== Generating Performance Baseline: $BASELINE_NAME ===" | tee "$LOG_FILE"
echo "Started at: $(date)" | tee -a "$LOG_FILE"
echo "Git commit: $(git rev-parse HEAD)" | tee -a "$LOG_FILE"
echo "" | tee -a "$LOG_FILE"

# Run full benchmark suite
echo "Running benchmarks..." | tee -a "$LOG_FILE"
cargo bench --message-format=json 2>&1 | tee -a "$LOG_FILE" | while read line; do
    if echo "$line" | jq -e ".reason == \"benchmark-complete\"" > /dev/null 2>&1; then
        name=$(echo "$line" | jq -r ".id")
        mean=$(echo "$line" | jq -r ".mean.estimate")
        echo "  $name: ${mean}ns" | tee -a "$LOG_FILE"
    fi
done

# Save baseline
cp -r target/criterion "$BASELINE_DIR/$BASELINE_NAME"

echo "" | tee -a "$LOG_FILE"
echo "=== Baseline saved to: $BASELINE_DIR/$BASELINE_NAME ===" | tee -a "$LOG_FILE"
echo "Completed at: $(date)" | tee -a "$LOG_FILE"
```

### 3. Regression Detection Script

Create `scripts/benchmark_regression.sh`:

```bash
#\!/bin/bash
# Compare current performance against baseline
# Usage: ./scripts/benchmark_regression.sh [baseline_name] [threshold_percent]

set -euo pipefail

BASELINE="${1:-main}"
THRESHOLD="${2:-10}"
LOG_FILE="target/benchmark_regression.log"

echo "=== Performance Regression Check ===" | tee "$LOG_FILE"
echo "Comparing against baseline: $BASELINE" | tee -a "$LOG_FILE"
echo "Regression threshold: ${THRESHOLD}%" | tee -a "$LOG_FILE"
echo "" | tee -a "$LOG_FILE"

# Run benchmarks with comparison
cargo bench -- --baseline "$BASELINE" 2>&1 | tee -a "$LOG_FILE" | while read line; do
    # Look for regression warnings
    if echo "$line" | grep -q "regressed"; then
        echo "⚠️  REGRESSION DETECTED: $line" | tee -a "$LOG_FILE"
    elif echo "$line" | grep -q "improved"; then
        echo "✅ Improvement: $line" | tee -a "$LOG_FILE"
    fi
done

# Check for regressions above threshold
REGRESSIONS=$(grep -c "regressed" "$LOG_FILE" 2>/dev/null || echo "0")

if [ "$REGRESSIONS" -gt 0 ]; then
    echo "" | tee -a "$LOG_FILE"
    echo "=== FAILED: $REGRESSIONS regressions detected ===" | tee -a "$LOG_FILE"
    exit 1
fi

echo "" | tee -a "$LOG_FILE"
echo "=== PASSED: No significant regressions ===" | tee -a "$LOG_FILE"
```

### 4. CI Integration

Create `.github/workflows/benchmark.yml`:

```yaml
name: Benchmarks

on:
  push:
    branches: [main]
  pull_request:
    branches: [main]

jobs:
  benchmark:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Install Rust
        uses: dtolnay/rust-action@stable

      - name: Cache criterion results
        uses: actions/cache@v4
        with:
          path: target/criterion
          key: criterion-${{ runner.os }}-${{ hashFiles("**/Cargo.lock") }}

      - name: Run benchmarks
        run: |
          cargo bench --message-format=json 2>&1 | tee benchmark_output.log

      - name: Check for regressions
        run: |
          if grep -q "regressed" benchmark_output.log; then
            echo "::warning::Performance regression detected"
            grep "regressed" benchmark_output.log
          fi

      - name: Upload benchmark results
        uses: actions/upload-artifact@v4
        with:
          name: benchmark-results
          path: target/criterion/
```

